<?php require_once '../config/db.php'; if(!isAdmin()) redirect('../login.php');
$totalCustomers = $pdo->query("SELECT COUNT(*) FROM CUSTOMER")->fetchColumn();
$totalBalance = $pdo->query("SELECT SUM(AvailableBalance) FROM ACCOUNT")->fetchColumn();
$totalTransactions = $pdo->query("SELECT COUNT(*) FROM TRANSACTION")->fetchColumn();
$pendingKYC = $pdo->query("SELECT COUNT(*) FROM CUSTOMERKYC WHERE KYCStatus='Pending'")->fetchColumn();
$customers = $pdo->query("SELECT c.*, a.AccountNumber, a.AvailableBalance FROM CUSTOMER c LEFT JOIN ACCOUNT a ON c.CustomerID=a.CustomerID ORDER BY c.CreatedAt DESC LIMIT 20")->fetchAll();
if(isset($_GET['action']) && isset($_GET['id'])) {
    $action=$_GET['action']; $id=$_GET['id'];
    if($action=='verify_kyc') $pdo->prepare("UPDATE CUSTOMERKYC SET KYCStatus='Verified',VerifiedDate=CURDATE() WHERE CustomerID=?")->execute([$id]);
    elseif($action=='freeze') $pdo->prepare("UPDATE ACCOUNT SET AccountStatus='Frozen' WHERE CustomerID=?")->execute([$id]);
    elseif($action=='activate') $pdo->prepare("UPDATE ACCOUNT SET AccountStatus='Active' WHERE CustomerID=?")->execute([$id]);
    redirect('index.php');
}
?>
<!DOCTYPE html><html><head><meta charset="UTF-8"><title>Admin - Asha Bank</title><link href="https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap" rel="stylesheet"><style>:root{--font-sans:'Inter',sans-serif;--bg:#fff;--bg2:#F8FAFC;--text:#0F172A;--text2:#475569;--border:#E2E8F0;--accent:#185FA5;--accent-bg:#E6F1FB;--success:#3B6D11;--danger:#A32D2D;}body.dark{--bg:#0F172A;--bg2:#1E293B;--text:#F1F5F9;--border:#334155;--accent:#3B82F6;}*{margin:0;padding:0;box-sizing:border-box;}body{font-family:var(--font-sans);background:var(--bg2);color:var(--text);padding:16px;}.topbar{background:var(--bg);border:0.5px solid var(--border);border-radius:16px;padding:12px 20px;display:flex;justify-content:space-between;margin-bottom:16px;}.stat-row{display:grid;grid-template-columns:repeat(4,1fr);gap:12px;margin-bottom:16px;}.stat-card{background:var(--bg);border:0.5px solid var(--border);border-radius:16px;padding:16px;}.stat-value{font-size:24px;font-weight:600;}.glass-card{background:var(--bg);border:0.5px solid var(--border);border-radius:16px;padding:20px;margin-bottom:16px;}table{width:100%;border-collapse:collapse;}th,td{padding:10px;text-align:left;border-bottom:0.5px solid var(--border);}th{color:var(--text2);font-size:12px;}.btn{padding:4px 10px;border-radius:20px;font-size:11px;text-decoration:none;display:inline-block;margin:2px;}.btn-success{background:var(--success);color:#fff;}.btn-warning{background:#BA7517;color:#fff;}.btn-danger{background:var(--danger);color:#fff;}.toggle-pill{position:fixed;top:16px;right:16px;padding:5px 12px;border:0.5px solid var(--border);border-radius:20px;background:var(--bg);cursor:pointer;}</style></head><body><div class="toggle-pill" id="themeToggle">🌓 Dark/Light</div><div class="topbar"><h2><span style="color:var(--accent)">Admin</span> Dashboard</h2><div>Welcome, <?= $_SESSION['username'] ?></div></div><div class="stat-row"><div class="stat-card"><div class="stat-label">Total Customers</div><div class="stat-value"><?= $totalCustomers ?></div></div><div class="stat-card"><div class="stat-label">Total Balance</div><div class="stat-value"><?= formatBDT($totalBalance) ?></div></div><div class="stat-card"><div class="stat-label">Transactions</div><div class="stat-value"><?= $totalTransactions ?></div></div><div class="stat-card"><div class="stat-label">Pending KYC</div><div class="stat-value"><?= $pendingKYC ?></div></div></div><div class="glass-card"><h3>Customer Management</h3><div style="overflow-x:auto"><table><thead><tr><th>ID</th><th>Name</th><th>Email</th><th>Phone</th><th>Account</th><th>Balance</th><th>Actions</th></tr></thead><tbody><?php foreach($customers as $c): ?><tr><td><?= $c['CustomerID'] ?></td><td><?= $c['FirstName'].' '.$c['LastName'] ?></td><td><?= $c['Email'] ?></td><td><?= $c['Phone'] ?></td><td><?= $c['AccountNumber'] ?? 'N/A' ?></td><td><?= formatBDT($c['AvailableBalance']??0) ?></td><td><a href="?action=verify_kyc&id=<?= $c['CustomerID'] ?>" class="btn btn-success">Verify KYC</a><a href="?action=freeze&id=<?= $c['CustomerID'] ?>" class="btn btn-warning">Freeze</a><a href="?action=activate&id=<?= $c['CustomerID'] ?>" class="btn btn-success">Activate</a></td></tr><?php endforeach; ?></tbody></table></div></div><script>let isDark=localStorage.getItem('theme')==='dark';function toggleTheme(){isDark=!isDark;if(isDark)document.body.classList.add('dark');else document.body.classList.remove('dark');localStorage.setItem('theme',isDark?'dark':'light');}document.getElementById('themeToggle').addEventListener('click',toggleTheme);if(localStorage.getItem('theme')==='dark')document.body.classList.add('dark');</script></body></html>